class MessageProcessorActor extends Actor with ActorLogging {
  val deserializer = new SafeMessageDeserializer()
  
  def receive: Receive = {
    case jsonString: String =>
      deserializer.deserializeFromJson(jsonString) match {
        case Success(msg) if deserializer.validateMessage(msg) =>
