          log.warning(s"Invalid message received: $msg")
          sender() ! ErrorMessage("Message validation failed")
        case Failure(ex) =>
          log.error(ex, "Failed to deserialize message")
          sender() ! ErrorMessage(s"Deserialization error: ${ex.getMessage}")
      }
    
