      if (deserializer.validateMessage(msg)) {
        processMessage(msg)
      } else {
        log.warning(s"Invalid message received: $msg")
        sender() ! ErrorMessage("Message validation failed")
      }
    
    case unknown =>
      log.warning(s"Unknown message type: ${unknown.getClass.getName}")
      sender() ! ErrorMessage("Unknown message type")
  }
  
  private def processMessage(msg: SafeMessage): Unit = {
    msg match {
      case TextMessage(content) =>
        log.info(s"Processing text message: $content")
        sender() ! TextMessage(s"Processed: $content")
      
      case NumericMessage(value) =>
        log.info(s"Processing numeric message: $value")
        sender() ! NumericMessage(value * 2)
      
      case DataMessage(key, value, timestamp) =>
        log.info(s"Processing data message: key=$key, value=$value, timestamp=$timestamp")
        sender() ! DataMessage(key, s"Processed: $value", System.currentTimeMillis())
      
      case ErrorMessage(error) =>
        log.error(s"Error message received: $error")
    }
  }
